<?php require_once '../config/db.php'; if(!isStaff()) redirect('../login.php');
$pendingKYC = $pdo->query("SELECT COUNT(*) FROM CUSTOMERKYC WHERE KYCStatus='Pending'")->fetchColumn();
$todayTrans = $pdo->query("SELECT COUNT(*) FROM TRANSACTION WHERE DATE(TransactionDate)=CURDATE()")->fetchColumn();
$pendingKYCCustomers = $pdo->query("SELECT c.*,k.KYCStatus FROM CUSTOMER c JOIN CUSTOMERKYC k ON c.CustomerID=k.CustomerID WHERE k.KYCStatus='Pending' LIMIT 10")->fetchAll();
if(isset($_GET['verify'])){$pdo->prepare("UPDATE CUSTOMERKYC SET KYCStatus='Verified',VerifiedDate=CURDATE() WHERE CustomerID=?")->execute([$_GET['verify']]); redirect('dashboard.php');}
?>
<!DOCTYPE html><html><head><meta charset="UTF-8"><title>Staff - Asha Bank</title><link href="https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&display=swap" rel="stylesheet"><style>:root{--font-sans:'Inter',sans-serif;--bg:#fff;--bg2:#F8FAFC;--text:#0F172A;--border:#E2E8F0;--accent:#185FA5;--accent-bg:#E6F1FB;--success:#3B6D11;--warn:#BA7517;}body.dark{--bg:#0F172A;--bg2:#1E293B;--text:#F1F5F9;--border:#334155;--accent:#3B82F6;}*{margin:0;padding:0;box-sizing:border-box;}body{font-family:var(--font-sans);background:var(--bg2);color:var(--text);padding:16px;}.topbar{background:var(--bg);border:0.5px solid var(--border);border-radius:16px;padding:12px 20px;display:flex;justify-content:space-between;margin-bottom:16px;}.stat-row{display:grid;grid-template-columns:repeat(3,1fr);gap:12px;margin-bottom:16px;}.stat-card{background:var(--bg);border:0.5px solid var(--border);border-radius:16px;padding:16px;}.stat-value{font-size:24px;font-weight:600;}.glass-card{background:var(--bg);border:0.5px solid var(--border);border-radius:16px;padding:20px;margin-bottom:16px;}table{width:100%;border-collapse:collapse;}th,td{padding:10px;text-align:left;border-bottom:0.5px solid var(--border);}.btn{padding:4px 12px;border-radius:20px;font-size:11px;text-decoration:none;background:var(--success);color:#fff;display:inline-block;}.toggle-pill{position:fixed;top:16px;right:16px;padding:5px 12px;border:0.5px solid var(--border);border-radius:20px;background:var(--bg);cursor:pointer;}</style></head><body><div class="toggle-pill" id="themeToggle">🌓 Dark/Light</div><div class="topbar"><h2><span style="color:var(--warn)">Staff</span> Dashboard</h2><div>Welcome, <?= $_SESSION['username'] ?></div></div><div class="stat-row"><div class="stat-card"><div class="stat-label">Pending KYC</div><div class="stat-value"><?= $pendingKYC ?></div></div><div class="stat-card"><div class="stat-label">Today's Transactions</div><div class="stat-value"><?= $todayTrans ?></div></div><div class="stat-card"><div class="stat-label">Active Customers</div><div class="stat-value"><?= $pdo->query("SELECT COUNT(*) FROM CUSTOMER WHERE IsActive=1")->fetchColumn() ?></div></div></div><div class="glass-card"><h3>Pending KYC Verification</h3><?php if(empty($pendingKYCCustomers)): ?><p>No pending KYC requests</p><?php else: ?><div style="overflow-x:auto"><tr><thead><tr><th>ID</th><th>Name</th><th>Email</th><th>Phone</th><th>Action</th></tr></thead><tbody><?php foreach($pendingKYCCustomers as $c): ?><tr><td><?= $c['CustomerID'] ?></td><td><?= $c['FirstName'].' '.$c['LastName'] ?></td><td><?= $c['Email'] ?></td><td><?= $c['Phone'] ?></td><td><a href="?verify=<?= $c['CustomerID'] ?>" class="btn">Verify KYC</a></td></tr><?php endforeach; ?></tbody></table></div><?php endif; ?></div><script>let isDark=localStorage.getItem('theme')==='dark';function toggleTheme(){isDark=!isDark;if(isDark)document.body.classList.add('dark');else document.body.classList.remove('dark');localStorage.setItem('theme',isDark?'dark':'light');}document.getElementById('themeToggle').addEventListener('click',toggleTheme);if(localStorage.getItem('theme')==='dark')document.body.classList.add('dark');</script></body></html>